INSERT INTO location_names(region, city)
SELECT 'ԱՐԱԳԱԾՈՏՆ', 'ASHTARAK' FROM DUAL
WHERE NOT EXISTS (SELECT 1 FROM location_names WHERE region='ԱՐԱԳԱԾՈՏՆ' AND city='ASHTARAK');
